/* 
SPI Manager Module.

This is the go-between for the SPI peripheral and the rest of the FPGA design.
It handles the two input/output FIFOs and muxes the input data to the correct
destination based on an internal state machine.

This has five main data paths:
    1) FPGA -> SPI: pixel data to send over SPI
    2) SPI -> FPGA: instructions
    3) SPI -> FPGA: start pointers
    4) SPI -> FPGA: weight memory data
    5) SPI -> FPGA: image data
The state machine cycles through the SPI -> FPGA paths in order, switching when
it receives a sentinel value (0x42) indicating the end of that section.
Notably, the SPI -> FPGA paths have different data widths, so we need to assemble
the incoming bytes into larger words before writing to the corresponding FIFOs.

TODO: handle overflow conditions on the FIFOs.
When we are in INST/SPTR/WMEM states, if the corresponding FIFO is full, we
will broadcast a 0x00 on the SPI MISO line until space is available.
 */

`timescale 1ns / 1ps
`default_nettype none

module spi_manager #(
    parameter DATA_WIDTH = 8,
    parameter FIFO_DEPTH = 16,

    parameter INST_WIDTH = 24,
    parameter SPTR_WIDTH = 8,
    parameter WMEM_WIDTH = 8,
    parameter IMG_WIDTH = 16 // DDR word size
)(
    input  wire                   clk,
    input  wire                   rst,

    // SPI Peripheral Interface
    input  wire                   spi_clk,
    input  wire                   spi_mosi,
    output logic                  spi_miso,
    input  wire                   spi_cs,

    // I/O with FPGA
    input wire write,                            // write signal for fpga -> spi
    input wire [DATA_WIDTH-1:0] pixel_to_send,   // data to send from fpga to spi
    output logic full,                           // wait up! still sending previous over spi

    input  wire read_inst,                       // read signal for spi -> fpga (advance fifo)
    output logic [INST_WIDTH-1:0] received_inst, // instruction received from spi
    output logic                  inst_valid,    // i have an instruction for you

    input  wire read_sptr,
    output logic [SPTR_WIDTH-1:0] received_sptr,
    output logic                  sptr_valid,

    input  wire read_wmem,
    output logic [WMEM_WIDTH-1:0] received_wmem,
    output logic                  wmem_valid,

    input  wire read_img,
    output logic [IMG_WIDTH-1:0] received_img,
    output logic                 img_valid
);

    // state machine to determine which part of the FPGA gets the SPI data
    enum {
        READ_INST,
        READ_SPTR,
        READ_WMEM,
        READ_IMG
    } read_state;

    // fifos (spi --> fpga)
    logic write_inst, write_sptr, write_wmem, write_img;
    logic full_inst, full_sptr, full_wmem, full_img;
    logic [INST_WIDTH-1:0] command_in_inst;
    logic [SPTR_WIDTH-1:0] command_in_sptr;
    logic [WMEM_WIDTH-1:0] command_in_wmem;
    logic [IMG_WIDTH-1:0] command_in_img;

    command_fifo #(
        .DEPTH(FIFO_DEPTH),
        .WIDTH(INST_WIDTH)
    ) fifo_inst (
        .clk(clk),
        .rst(rst),
        .write(write_inst),
        .command_in(command_in_inst),
        .full(full_inst),

        .command_out(received_inst),
        .read(read_inst),
        .valid(inst_valid)
    );

    command_fifo #(
        .DEPTH(FIFO_DEPTH),
        .WIDTH(SPTR_WIDTH)
    ) fifo_sptr (
        .clk(clk),
        .rst(rst),
        .write(write_sptr),
        .command_in(command_in_sptr),
        .full(full_sptr),

        .command_out(received_sptr),
        .read(read_sptr),
        .valid(sptr_valid)
    );

    command_fifo #(
        .DEPTH(FIFO_DEPTH),
        .WIDTH(WMEM_WIDTH)
    ) fifo_wmem (
        .clk(clk),
        .rst(rst),
        .write(write_wmem),
        .command_in(command_in_wmem),
        .full(full_wmem),

        .command_out(received_wmem),
        .read(read_wmem),
        .valid(wmem_valid)
    );

    command_fifo #(
        .DEPTH(FIFO_DEPTH),
        .WIDTH(IMG_WIDTH)
    ) fifo_img (
        .clk(clk),
        .rst(rst),
        .write(write_img),
        .command_in(command_in_img),
        .full(full_img),

        .command_out(received_img),
        .read(read_img),
        .valid(img_valid)
    );

    // fifos (fpga --> spi)
    logic [DATA_WIDTH-1:0] spi_miso_out;
    logic spi_miso_valid;
    logic spi_miso_read;
    command_fifo #(
        .DEPTH(FIFO_DEPTH),
        .WIDTH(DATA_WIDTH)
    ) fifo_output (
        .clk(clk),
        .rst(rst),
        .write(write),
        .command_in(pixel_to_send),
        .full(full),

        .command_out(spi_miso_out),
        .read(spi_miso_read),
        .valid(spi_miso_valid)
    );

    // SPI peripheral instance
    logic [DATA_WIDTH-1:0] data_received;
    logic data_valid;
    spi_per #(
        .DATA_WIDTH(DATA_WIDTH)
    ) spi_per_inst (
        .clk(clk),
        .rst(rst),

        // SPI Interface
        .spi_clk(spi_clk),
        .spi_mosi(spi_mosi),
        .spi_miso(spi_miso),
        .spi_cs(spi_cs),

        // I/O with fpga
        .data_to_send(spi_miso_out),
        .data_to_send_valid(spi_miso_valid),
        .data_received(data_received),
        .data_valid(data_valid),
        .ready_for_data(spi_miso_read)
    );

    // state machine and data routing logic
    // because data comes in one byte at a time, we need to assemble
    // the larger commands from multiple bytes
    logic [3:0] byte_count;
    always_ff @(posedge clk) begin
        if (rst) begin
            // reset state machine
            read_state <= READ_INST;
            write_inst <= 0;
            write_sptr <= 0;
            write_wmem <= 0;
            write_img <= 0;
            command_in_inst <= '0;
            command_in_sptr <= '0;
            command_in_wmem <= '0;
            command_in_img <= '0;
            byte_count <= '0;
        end else begin
            // state machine transitions and data routing
            if (data_valid) begin
                // sentinel value = 0x42 indicates end of current section
                if (data_received == 8'h42) begin
                    case (read_state)
                        READ_INST: read_state <= READ_SPTR;
                        READ_SPTR: read_state <= READ_WMEM;
                        READ_WMEM: read_state <= READ_IMG;
                        READ_IMG: read_state <= READ_INST;
                    endcase
                    byte_count <= '0;
                end else begin
                    // route data to appropriate fifo based on state
                    case (read_state)
                        READ_INST: begin
                            command_in_inst <= {command_in_inst[INST_WIDTH-9:0], data_received};
                            if (byte_count == (INST_WIDTH / DATA_WIDTH) - 1) begin
                                write_inst <= 1;
                                byte_count <= '0;
                            end else begin
                                write_inst <= 0;
                                byte_count <= byte_count + 1;
                            end
                        end
                        READ_SPTR: begin
                            command_in_sptr <= data_received; // WARNING only works for 8 bit SPTR
                            if (byte_count == (SPTR_WIDTH / DATA_WIDTH) - 1) begin
                                write_sptr <= 1;
                                byte_count <= '0;
                            end else begin
                                write_sptr <= 0;
                                byte_count <= byte_count + 1;
                            end
                        end
                        READ_WMEM: begin
                            command_in_wmem <= data_received; // WARNING only works for 8 bit WMEM
                            if (byte_count == (WMEM_WIDTH / DATA_WIDTH) - 1) begin
                                write_wmem <= 1;
                                byte_count <= '0;
                            end else begin
                                write_wmem <= 0;
                                byte_count <= byte_count + 1;
                            end
                        end
                        READ_IMG: begin
                            command_in_img <= {command_in_img[IMG_WIDTH-9:0], data_received};
                            if (byte_count == (IMG_WIDTH / DATA_WIDTH) - 1) begin
                                write_img <= 1;
                                byte_count <= '0;
                            end else begin
                                write_img <= 0;
                                byte_count <= byte_count + 1;
                            end
                        end
                    endcase
                end
            end
        end
    end

endmodule // spi_manager
`default_nettype wire

